import os
import time
from datetime import datetime
from elasticsearch import Elasticsearch, NotFoundError
from elasticsearch.helpers import bulk

class CentralizedPlatform:
    def __init__(self, host='localhost', port=9200):
        self.es = Elasticsearch([{'host': host, 'port': port, 'scheme': 'http'}])
        self.INDEX_NAME = "my_central_platform"
        self.LOG_INDEX_NAME = "app_logs"

        if not self.es.ping():
            raise ValueError("Could not connect to Elasticsearch! Please ensure it is running.")
        print(f"Connected to Elasticsearch at {host}:{port}")

    def create_index(self, index_name, mappings=None):
        """Creates an Elasticsearch index with optional mappings."""
        if not self.es.indices.exists(index=index_name):
            self.es.indices.create(index=index_name, body={'mappings': mappings} if mappings else None)
            print(f"Index '{index_name}' created successfully.")
        else:
            print(f"Index '{index_name}' already exists.")

    def setup_indices(self):
        """Sets up the main document index and the log index."""
        # Mappings for the main search index
        doc_mappings = {
            "properties": {
                "title": {"type": "text"},
                "content": {"type": "text"},
                "tags": {"type": "keyword"},
                "timestamp": {"type": "date"}
            }
        }
        self.create_index(self.INDEX_NAME, doc_mappings)

        # Mappings for the log index
        log_mappings = {
            "properties": {
                "timestamp": {"type": "date"},
                "level": {"type": "keyword"},
                "message": {"type": "text"},
                "app_name": {"type": "keyword"},
                "trace_id": {"type": "keyword", "index": False} # Not searchable, just stored
            }
        }
        self.create_index(self.LOG_INDEX_NAME, log_mappings)

    def index_document(self, document, doc_id=None):
        """Indexes a single document into the main search index."""
        if "timestamp" not in document:
            document["timestamp"] = datetime.now()
        try:
            response = self.es.index(index=self.INDEX_NAME, id=doc_id, document=document)
            print(f"Document indexed: {response['_id']}")
            return response['_id']
        except Exception as e:
            print(f"Error indexing document: {e}")
            return None

    def bulk_index_documents(self, documents):
        """Indexes multiple documents using the bulk API."""
        actions = [
            {
                "_index": self.INDEX_NAME,
                "_id": doc.get('id'), # Use existing 'id' if present, otherwise ES generates one
                "_source": {**doc, "timestamp": doc.get("timestamp", datetime.now())}
            }
            for doc in documents
        ]
        try:
            success, failed = bulk(self.es, actions)
            print(f"Bulk indexing complete. Success: {success}, Failed: {failed}")
            return success, failed
        except Exception as e:
            print(f"Error during bulk indexing: {e}")
            return 0, len(documents)

    def search_documents(self, query_string, fields=None, size=10, highlight=False):
        """Performs a full-text search on documents."""
        search_body = {
            "query": {
                "multi_match": {
                    "query": query_string,
                    "fields": fields if fields else ["title^3", "content", "tags"] # Boost title field
                }
            },
            "size": size
        }

        if highlight:
            search_body["highlight"] = {
                "fields": {
                    field: {} for field in (fields if fields else ["title", "content"])
                },
                "pre_tags": ["<em>"],
                "post_tags": ["</em>"]
            }

        try:
            response = self.es.search(index=self.INDEX_NAME, body=search_body)
            print(f"\nSearch results for '{query_string}':")
            for hit in response['hits']['hits']:
                print(f"  ID: {hit['_id']}, Score: {hit['_score']}")
                print(f"  Source: {hit['_source']}")
                if highlight and 'highlight' in hit:
                    print(f"  Highlight: {hit['highlight']}")
            print(f"Total hits: {response['hits']['total']['value']}")
            return response
        except Exception as e:
            print(f"Error during search: {e}")
            return None

    def log_message(self, level, message, app_name="default_app", trace_id=None, extra_data=None):
        """Logs a message to the log aggregation index."""
        log_entry = {
            "timestamp": datetime.now(),
            "level": level.upper(),
            "message": message,
            "app_name": app_name
        }
        if trace_id:
            log_entry["trace_id"] = trace_id
        if extra_data and isinstance(extra_data, dict):
            log_entry.update(extra_data)

        try:
            response = self.es.index(index=self.LOG_INDEX_NAME, document=log_entry)
            # print(f"Log entry recorded: {response['_id']}")
            return response['_id']
        except Exception as e:
            print(f"Error logging message: {e}")
            return None

    def aggregate_logs(self, query_string=None, app_name=None, level=None, start_time=None, end_time=None, size=10):
        """
        Aggregates and searches logs based on various criteria.
        Includes example of a simple aggregation (e.g., count by level).
        """
        query_parts = []
        if query_string:
            query_parts.append({"match": {"message": query_string}})
        if app_name:
            query_parts.append({"term": {"app_name.keyword": app_name}})
        if level:
            query_parts.append({"term": {"level.keyword": level.upper()}})

        range_query = {}
        if start_time:
            range_query["gte"] = start_time.isoformat() if isinstance(start_time, datetime) else start_time
        if end_time:
            range_query["lte"] = end_time.isoformat() if isinstance(end_time, datetime) else end_time
        if range_query:
            query_parts.append({"range": {"timestamp": range_query}})

        search_body = {
            "query": {
                "bool": {
                    "must": query_parts if query_parts else [{"match_all": {}}]
                }
            },
            "sort": [{"timestamp": {"order": "desc"}}],
            "size": size,
            "aggs": {
                "logs_by_level": {
                    "terms": {
                        "field": "level.keyword"
                    }
                },
                "logs_by_app": {
                    "terms": {
                        "field": "app_name.keyword"
                    }
                },
                "hourly_log_count": {
                    "date_histogram": {
                        "field": "timestamp",
                        "fixed_interval": "1h",
                        "min_doc_count": 0
                    }
                }
            }
        }

        try:
            response = self.es.search(index=self.LOG_INDEX_NAME, body=search_body)
            print(f"\nLog Aggregation Results (Total hits: {response['hits']['total']['value']}):")
            for hit in response['hits']['hits']:
                print(f"  [{hit['_source']['timestamp']}] [{hit['_source']['level']}] ({hit['_source']['app_name']}): {hit['_source']['message']}")

            print("\nAggregations:")
            for agg_name, agg_data in response['aggregations'].items():
                print(f"  {agg_name}:")
                if 'buckets' in agg_data:
                    for bucket in agg_data['buckets']:
                        key = bucket.get('key_as_string', bucket['key'])
                        print(f"    - {key}: {bucket['doc_count']}")
            return response
        except Exception as e:
            print(f"Error during log aggregation: {e}")
            return None

    def delete_index(self, index_name):
        """Deletes an Elasticsearch index."""
        try:
            if self.es.indices.exists(index=index_name):
                self.es.indices.delete(index=index_name)
                print(f"Index '{index_name}' deleted successfully.")
            else:
                print(f"Index '{index_name}' does not exist.")
        except Exception as e:
            print(f"Error deleting index '{index_name}': {e}")

    def clear_all_data(self):
        """Deletes both main and log indices."""
        self.delete_index(self.INDEX_NAME)
        self.delete_index(self.LOG_INDEX_NAME)

